Iteratively insert each shipment into the assign that yields the lowest marginal cost increase among feasible candidates, using a fallback empty assign creation if no existing assign accepts it.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx        int
		deltaCost  float64
		assignIdx  int
	}
	for jj := 0; jj < len(oris); jj++ {
		best := candidate{idx: -1, deltaCost: 1e18, assignIdx: -1}
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj
		for ai := 0; ai < MAXASSIGNS; ai++ {
			if ai >= dispatch.AssignsLen && ai != dispatch.AssignsLen {
				continue
			}
			origCost := dispatch.Assigns[ai].Cost
			ok := dispatch.Assigns[ai].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				if newCost >= 0 {
					delta := newCost - origCost
					if delta < best.deltaCost {
						best.deltaCost = delta
						best.assignIdx = ai
						best.idx = ai
					}
				}
			}
			dispatch.Assigns[ai].RemoveShip(shipID)
			dispatch.Assigns[ai].GenRoute()
		}
		targetAssign := best.assignIdx
		if targetAssign == -1 {
			targetAssign = dispatch.AssignsLen
			if targetAssign >= MAXASSIGNS {
				continue
			}
		}
		success := dispatch.Assigns[targetAssign].AddShip(shipID, ori, des)
		if success {
			dispatch.Assigns[targetAssign].GenRoute()
			if targetAssign >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
		} else {
			dispatch.Assigns[targetAssign].RemoveShip(shipID)
			dispatch.Assigns[targetAssign].GenRoute()
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

