Modified greedy insertion with fallback: try inserting each ship into all existing routes and one new empty route using cheapest feasible position selection, if none work then force insert into a new route at end.}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	shipIDOffset := total_ship
	orderCount := len(oris)
	if orderCount != len(dess) || orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	for jj := 0; jj < orderCount; jj++ {
		ori := oris[jj]
		des := dess[jj]
		bestIdx := -1
		bestDeltaCost := math.MaxFloat64
		savedAssigns := make([]Assign, dispatch.AssignsLen)

		// Try inserting into existing non-empty assigns first
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			if dispatch.Assigns[ii].StationsLen == 0 {
				continue
			}
			savedAssigns[ii] = dispatch.Assigns[ii]
			prevCost := dispatch.Assigns[ii].Cost
			added := dispatch.Assigns[ii].AddShip(shipIDOffset+jj, ori, des)
			if added {
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					delta := dispatch.Assigns[ii].Cost - prevCost
					if delta < bestDeltaCost {
						bestDeltaCost = delta
						bestIdx = ii
					}
				}
			}
			dispatch.Assigns[ii] = savedAssigns[ii]
		}

		// Also consider the next available new assign slot if within bounds
		newSlotIdx := dispatch.AssignsLen
		if newSlotIdx < MAXASSIGNS {
			savedNew := dispatch.Assigns[newSlotIdx]
			prevCost := dispatch.Assigns[newSlotIdx].Cost
			added := dispatch.Assigns[newSlotIdx].AddShip(shipIDOffset+jj, ori, des)
			if added {
				dispatch.Assigns[newSlotIdx].GenRoute()
				if dispatch.Assigns[newSlotIdx].Cost >= 0 {
					delta := dispatch.Assigns[newSlotIdx].Cost - prevCost
					if delta < bestDeltaCost {
						bestDeltaCost = delta
						bestIdx = newSlotIdx
					}
				}
			}
			dispatch.Assigns[newSlotIdx] = savedNew
		}

		inserted := false
		if bestIdx >= 0 {
			// Perform actual insertion at bestIdx
			actualAdded := dispatch.Assigns[bestIdx].AddShip(shipIDOffset+jj, ori, des)
			if actualAdded {
				dispatch.Assigns[bestIdx].GenRoute()
				if dispatch.Assigns[bestIdx].Cost >= 0 {
					if bestIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen++
					}
					inserted = true
				} else {
					dispatch.Assigns[bestIdx].RemoveShip(shipIDOffset + jj)
					dispatch.Assigns[bestIdx].GenRoute()
				}
			}
		}

		if !inserted {
			// Fallback: find any available slot (including new ones) and force attempt
			fallbackIdx := -1
			for ii := 0; ii <= dispatch.AssignsLen; ii++ {
				if ii >= MAXASSIGNS {
					break
				}
				prevLen := dispatch.Assigns[ii].StationsLen
				prevCost := dispatch.Assigns[ii].Cost
				added := dispatch.Assigns[ii].AddShip(shipIDOffset+jj, ori, des)
				if added {
					dispatch.Assigns[ii].GenRoute()
					if dispatch.Assigns[ii].Cost >= 0 {
						fallbackIdx = ii
						inserted = true
						break
					} else {
						dispatch.Assigns[ii].RemoveShip(shipIDOffset + jj)
						dispatch.Assigns[ii].GenRoute()
					}
				}
			}
			if fallbackIdx >= 0 && fallbackIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

